const ENGINE = $env.ENGINE_URL;
const SLACK = $env.SLACK_WEBHOOK_URL;
const jobId = ($input.first().json.query || {}).job_id;
if (!jobId) { return [{ json: { error: 'missing job_id query param' } }]; }
await this.helpers.httpRequest({ method: 'POST', url: ENGINE + '/jobs/' + jobId + '/approve', json: true });
const DONE = ['published', 'sent'];
const TERMINAL = ['optimized', 'failed', 'revision_needed', 'halted_budget'];
let status = '';
for (let i = 0; i < 30; i++) {
  const t = await this.helpers.httpRequest({ method: 'POST', url: ENGINE + '/tick', json: true });
  const j = await this.helpers.httpRequest({ method: 'GET', url: ENGINE + '/jobs/' + jobId, json: true });
  status = j.status;
  if (DONE.includes(status) || TERMINAL.includes(status)) break;
  if (!t.advanced) break;
  await new Promise(r => setTimeout(r, 300));
}
if (SLACK) {
  await this.helpers.httpRequest({ method: 'POST', url: SLACK, body: { text: 'Job ' + jobId + ' is now ' + status + '. Measurement runs automatically after the configured window (MEASURE_AFTER_DAYS).' }, json: true });
}
return [{ json: { ok: true, job_id: jobId, status: status } }];
